#!/usr/bin/env python3
"""Apply script: Writer Room Enrichments v1.

Three enhancements for the creative layer:
1. Player position in bullets (deterministic_bullets_v1.py - MODIFIED)
2. bid_amount key fix for FAAB display (deterministic_bullets_v1.py - MODIFIED)
3. Scoring deltas + FAAB spending (writer_room_context_v1.py - NEW)

17 new tests.

Usage (from repo root):
    python scripts/apply_writer_room_enrichments_v1.py

Verified against: 1083 passed, 3 skipped
"""
import base64
import json
import os
import sys
from pathlib import Path

MANIFEST = json.loads("""{"src/squadvault/core/recaps/render/deterministic_bullets_v1.py": "", "src/squadvault/core/recaps/context/writer_room_context_v1.py": "", "Tests/test_writer_room_enrichments_v1.py": ""}""")

def _find_repo_root() -> Path:
    script_dir = Path(__file__).resolve().parent
    if script_dir.name == "scripts" and (script_dir.parent / "src" / "squadvault").is_dir():
        return script_dir.parent
    cwd = Path.cwd()
    if (cwd / "src" / "squadvault").is_dir():
        return cwd
    return None

def main():
    repo_root = _find_repo_root()
    if repo_root is None:
        print("ERROR: Cannot find src/squadvault/")
        sys.exit(1)

    print(f"Repo root: {repo_root}")
    print(f"Applying Writer Room Enrichments v1 (3 files, 1 modified + 2 new)...")
    print()

    for rel_path, b64_content in MANIFEST.items():
        target = repo_root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content)} bytes)")

    print()
    print("All files written. Run:")
    print("  PYTHONPATH=src python -m pytest Tests/test_writer_room_enrichments_v1.py -v")
    print("  PYTHONPATH=src python -m pytest Tests/ -q")

if __name__ == "__main__":
    main()
